#include<bits/stdc++.h>
using namespace std;
long long f[100010];
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    if(n>m)
    {
        swap(n,m);
    }
    for(int i=n;i>=1;i--)
    {
        f[i]=1ll*(n/i)*(m/i);
        for(int j=2*i;j<=n;j+=i)
        {
            f[i]-=f[j];
        }
    }
    long long ans=0;
    for(int i=1;i<=n;i++)
    {
        ans+=1ll*(2*i-1)*f[i];
    }
    printf("%lld",ans);
    return 0;
}
